    text-align: center;
}
.blessing {
    color: #8C7B6E;
    font-size: 24px;
    text-align: center;
    margin: 15px 0;
}
.image-container {
    width: 360px;
    height: 360px;
    background-image: url('https://via.placeholder.com/360x360');
    background-size: cover;
