<body>
<div class="card">
    <div class="header">中秋贺卡</div>
    <div class="subtitle">Zhōng Qiū</div>
    <div class="subtitle">Mid-Autumn Festival</div>
    <div class="separator"></div>
    <div class="blessing">月圆人圆，喜乐团圆</div>
    <div class="separator"></div>
    <div class="image-container"></div>
